#include <stdio.h>
#include <string.h>
#define MOD 1000000007

int countBalancedStrings(char *s) {
    int n = strlen(s);
    int count4 = 0, count7 = 0;
    for (int i = 0; i < n; i++) {
        if (s[i] == '4') count4++;
        else count7++;
    }

    int dp[n + 1][n + 1];
    memset(dp, 0, sizeof(dp));
    dp[0][0] = 1;

    for (int i = 1; i <= n; i++) {
        for (int j = 0; j <= i; j++) {
            if (j > 0) dp[i][j] = (dp[i][j] + dp[i - 1][j - 1]) % MOD;
            if (j < i) dp[i][j] = (dp[i][j] + dp[i - 1][j]) % MOD;
        }
    }

    int result = 0;
    for (int i = 0; i < n; i++) {
        int left4 = 0, left7 = 0;
        for (int j = 0; j < i; j++) {
            if (s[j] == '4') left4++;
            else left7++;
        }
        int right4 = count4 - left4, right7 = count7 - left7;
        if (left4 <= right7 && left7 <= right4) {
            result = (result + dp[i][left4] * dp[n - i - 1][left7] % MOD) % MOD;
        }
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[5005];
        scanf("%s", s);
        printf("%d\n", countBalancedStrings(s));
    }
    return 0;
}

