def count_balanced_strings(s):
    n = len(s)
    count4 = s.count('4')
    count7 = s.count('7')

    dp = [[0] * (n + 1) for _ in range(n + 1)]
    dp[0][0] = 1

    for i in range(1, n + 1):
        for j in range(i + 1):
            if j > 0:
                dp[i][j] = (dp[i][j] + dp[i - 1][j - 1]) % 1000000007
            if j < i:
                dp[i][j] = (dp[i][j] + dp[i - 1][j]) % 1000000007

    result = 0
    for i in range(n):
        left4 = s[:i].count('4')
        left7 = s[:i].count('7')
        right4 = count4 - left4
        right7 = count7 - left7
        if left4 <= right7 and left7 <= right4:
            result = (result + dp[i][left4] * dp[n - i - 1][left7] % 1000000007) % 1000000007
    return result

